import { useState, useCallback, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import ShpeHatAnimation from './ShpeHatAnimation';

const SHPE_RED = '#C8102E';
const SHPE_BLUE = '#003087';

const textVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.2, delayChildren: 0.1 },
  },
};

const lineVariants = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: 'easeOut' } },
};

export default function Home() {
  const [stage, setStage] = useState('video'); // 'video' | 'hat'
  const [fadeOut, setFadeOut] = useState(false);
  const [hatDone, setHatDone] = useState(false);
  const videoRef = useRef(null);

  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.playbackRate = 1.5;
    }
  }, []);

  const handleVideoEnd = useCallback(() => {
    setFadeOut(true);
    setTimeout(() => {
      setFadeOut(false);
      setStage('hat');
    }, 600);
  }, []);

  const handleHatComplete = useCallback(() => {
    setHatDone(true);
  }, []);

  return (
    <main className="font-sans">
      {stage === 'video' && (
        <div
          style={{
            transition: 'opacity 0.6s ease',
            opacity: fadeOut ? 0 : 1,
            width: '100%',
            height: '100vh',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            overflow: 'hidden',
          }}
        >
          <video
            ref={videoRef}
            src={require('../assets/shpe_animated_video.mp4')}
            autoPlay
            muted
            playsInline
            onEnded={handleVideoEnd}
            style={{ width: '100%', height: '100%', objectFit: 'cover' }}
          />
        </div>
      )}

      {stage === 'hat' && (
        <div
          style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minHeight: '100vh',
            gap: 0,
          }}
        >
          <AnimatePresence>
            {hatDone && (
              <motion.div
                variants={textVariants}
                initial="hidden"
                animate="visible"
                style={{ textAlign: 'center' }}
              >
                <motion.p
                  variants={lineVariants}
                  style={{ color: SHPE_RED, letterSpacing: '0.25em', fontSize: '1rem', fontWeight: 600, textTransform: 'uppercase', marginBottom: '0.25rem' }}
                >
                  Bienvenido a
                </motion.p>
                <motion.h1
                  variants={lineVariants}
                  style={{
                    fontSize: 'clamp(4rem, 12vw, 9rem)',
                    fontWeight: 900,
                    lineHeight: 1,
                    background: `linear-gradient(135deg, ${SHPE_RED} 0%, ${SHPE_BLUE} 100%)`,
                    WebkitBackgroundClip: 'text',
                    WebkitTextFillColor: 'transparent',
                    backgroundClip: 'text',
                  }}
                >
                  SHPE
                </motion.h1>
                <motion.div
                  variants={lineVariants}
                  style={{
                    width: '80px',
                    height: '4px',
                    borderRadius: '2px',
                    background: `linear-gradient(90deg, ${SHPE_RED}, ${SHPE_BLUE})`,
                    margin: '0.75rem auto',
                  }}
                />
                <motion.h2
                  variants={lineVariants}
                  style={{ color: SHPE_BLUE, fontSize: 'clamp(1rem, 2.5vw, 1.5rem)', fontWeight: 700 }}
                >
                  Society of Hispanic Professional Engineers
                </motion.h2>
                <motion.p
                  variants={lineVariants}
                  style={{ color: SHPE_RED, fontSize: 'clamp(0.9rem, 2vw, 1.25rem)', fontWeight: 600, marginTop: '0.25rem' }}
                >
                  Austin Chapter
                </motion.p>
              </motion.div>
            )}
          </AnimatePresence>

          <div style={{ marginTop: '-60px' }}>
            <ShpeHatAnimation onComplete={handleHatComplete} speed={1.4} />
          </div>
        </div>
      )}
    </main>
  );
}
